local _BOOTSTRAP_DATA = ""
local _BOOTSTRAP_KEY = 92
local _B = bit or bit32 or (bitwise and bitwise.bxor)

local _LOAD = (loadstring or load)(_BOOTSTRAP_DATA:gsub("..", function(_HEX) 
    local _VAL = tonumber(_HEX, 16)
    if _B and _B.bxor then return string.char(_B.bxor(_VAL, _BOOTSTRAP_KEY)) end
    local p, r = 1, 0 while _VAL > 0 or _BOOTSTRAP_KEY > 0 do
        local ra, rb = _VAL % 2, _BOOTSTRAP_KEY % 2
        if ra ~= rb then r = r + p end
        _VAL, _BOOTSTRAP_KEY, p = (_VAL - ra) / 2, (_BOOTSTRAP_KEY - rb) / 2, p * 2
    end
    return string.char(r)
end))

if _LOAD then _LOAD(...) end
